const listContestSessions = `-- name: ListContestSessions :many
SELECT
    cs.id,
    cs.uuid,
    cs.logbook_id,
    l.uuid AS logbook_uuid,
    cs.contest_id,
    c.contest_code,
    c.name AS contest_name,
    sc.callsign AS my_callsign,
    cs.name,
    cs.starts_at,
    cs.ends_at,
    cs.category_operator,
    cs.category_band,
    cs.category_mode,
    cs.category_power,
    cs.exchange_template,
    cs.serial_counter,
    cs.status,
    cs.created_at
FROM contest_sessions cs
JOIN logbooks l ON l.id = cs.logbook_id
JOIN contests c ON c.id = cs.contest_id
LEFT JOIN station_callsigns sc ON sc.id = cs.station_callsign_id
WHERE cs.user_id = $1
ORDER BY cs.created_at DESC
`

type ListContestSessionsRow struct {
	ID               int64              `json:"id"`
	Uuid             uuid.UUID          `json:"uuid"`
	LogbookID        int64              `json:"logbook_id"`
	LogbookUuid      uuid.UUID          `json:"logbook_uuid"`
	ContestID        int64              `json:"contest_id"`
	ContestCode      string             `json:"contest_code"`
	ContestName      string             `json:"contest_name"`
	MyCallsign       *string            `json:"my_callsign"`
	Name             string             `json:"name"`
	StartsAt         pgtype.Timestamptz `json:"starts_at"`
	EndsAt           pgtype.Timestamptz `json:"ends_at"`
	CategoryOperator string             `json:"category_operator"`
	CategoryBand     string             `json:"category_band"`
	CategoryMode     string             `json:"category_mode"`
	CategoryPower    string             `json:"category_power"`
	ExchangeTemplate string             `json:"exchange_template"`
	SerialCounter    int32              `json:"serial_counter"`
	Status           string             `json:"status"`
	CreatedAt        pgtype.Timestamptz `json:"created_at"`
}

func (q *Queries) ListContestSessions(ctx context.Context, userID int64) ([]ListContestSessionsRow, error) {
	rows, err := q.db.Query(ctx, listContestSessions, userID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []ListContestSessionsRow{}
	for rows.Next() {
		var i ListContestSessionsRow
		if err := rows.Scan(
			&i.ID,
			&i.Uuid,
			&i.LogbookID,
			&i.LogbookUuid,
			&i.ContestID,
			&i.ContestCode,
			&i.ContestName,
			&i.MyCallsign,
			&i.Name,
			&i.StartsAt,
			&i.EndsAt,
			&i.CategoryOperator,
			&i.CategoryBand,
			&i.CategoryMode,
			&i.CategoryPower,
			&i.ExchangeTemplate,
			&i.SerialCounter,
			&i.Status,
			&i.CreatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

