const upsertContest = `-- name: UpsertContest :one
INSERT INTO contests (contest_code, name, cabrillo_name, exchange_schema)
VALUES (
    UPPER(BTRIM($1::text)),
    $2::text,
    UPPER(BTRIM($1::text)),
    '{}'::jsonb
)
ON CONFLICT (contest_code) DO UPDATE
    SET name = EXCLUDED.name
RETURNING id, contest_code, name, cabrillo_name, exchange_schema, active
`

type UpsertContestParams struct {
	ContestCode string `json:"contest_code"`
	Name        string `json:"name"`
}

type UpsertContestRow struct {
	ID             int64  `json:"id"`
	ContestCode    string `json:"contest_code"`
	Name           string `json:"name"`
	CabrilloName   string `json:"cabrillo_name"`
	ExchangeSchema []byte `json:"exchange_schema"`
	Active         bool   `json:"active"`
}

// Auto-provision a contest record by ADIF contest code.
// Inserts if not present; returns existing record if already there.
func (q *Queries) UpsertContest(ctx context.Context, arg UpsertContestParams) (UpsertContestRow, error) {
	row := q.db.QueryRow(ctx, upsertContest, arg.ContestCode, arg.Name)
	var i UpsertContestRow
	err := row.Scan(
		&i.ID,
		&i.ContestCode,
		&i.Name,
		&i.CabrilloName,
		&i.ExchangeSchema,
		&i.Active,
	)
	return i, err
}
